<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Billiard Game</title>
    <style>
        body {
            margin: 0;
            padding: 0;
            background-color: #f0f0f0;
        }

        canvas {
            border: 1px solid #ccc;
            display: block;
        }

        h2 {
            text-align: center;
            font-family: Arial, sans-serif;
        }
    </style>
</head>
<body>
    <h2>Top-Down Billiard Game</h2>

    <!-- Physics simulation window -->
    <script type="text/javascript">
        const W = 800; // playfield width in pixels
        const H = 600; // playfield height in pixels
        const R = 50;   // ball radius in pixels
        const FRICTION = 0.5; // linear friction coefficient (pixels/sec)

        // Ball properties: x, y, vx, vy, cue (boolean for cue ball)
        let balls = [
            {x: 100, y: 50, vx: 0, vy: 0, cue: false},
            {x: 200, y: 150, vx: 0, vy: 0, cue: false},
            {x: 300, y: 250, vx: 0, vy: 0, cue: false}
        ];

        // State array for all balls
        let state = [...balls];

        // Function to reset balls
        window.sim.reset(balls) = function() {
            balls.forEach(function(ball) {
                ball.x = ball.originalX;
                ball.y = ball.originalY;
                ball.vx = ball.originalVx;
                ball.vy = ball.originalVy;
                ball.cue = ball.cue || false; // reset cue
            });
        };

        // Function to step physics by dt seconds
        window.sim.step(dt) => {
            const dtTime = (dt * 1000) / 60; // convert to milliseconds per second for consistency

            // Update velocities based on friction and collision forces
            balls.forEach(function(ball, index) {
                ball.vx += FRICTION * ball.vx;
                ball.vy += FRICTION * ball.vy;

                // Check collisions with walls (reflection)
                if (ball.x < R || ball.x > W - R) {
                    ball.vx = -ball.vx; // reflect x-component
                }
            });

            // Update positions based on velocities
            balls.forEach(function(ball, index) {
                ball.x += ball.vx * dtTime;
                ball.y += ball.vy * dtTime;

                // Check collisions with other balls (elastic collision)
                for (let i = 0; i < balls.length; i++) {
                    if (i === index) continue;

                    const dx = ball.x - balls[i].x;
                    const dy = ball.y - balls[i].y;
                    const distance = Math.sqrt(dx*dx + dy*dy);

                    // Check if balls are within collision range
                    if (distance < R * 2) { // assuming all balls have radius R for simplicity
                        const sumRadius = R * 2; // sum of radii for elastic collision

                        if (Math.abs(dx) + Math.abs(dy) > sumRadius) {
                            // Collision detected, update velocities using relative velocity formula
                            const relativeVelocityX = balls[i].vx - ball.vx;
                            const relativeVelocityY = balls[i].vy - ball.vy;

                            ball.vx += relativeVelocityX * dtTime / distance;
                            ball.vy += relativeVelocityY * dtTime / distance;
                        }
                    }
                }
            });

            // Check for pockets (center reaches a pocket)
            state.forEach(function(ball, index) {
                const x = balls[index].x + balls[index].vx * dtTime;
                const y = balls[index].y + balls[index].vy * dtTime;

                if (Math.abs(x - R) < 10 && Math.abs(y - H - R) < 10) { // pockets at corners
                    ball.potted = true; // mark as out of play
                }
            });

            // Check for potted balls and reset if needed
            state.forEach(function(ball, index) {
                const x = balls[index].x + balls[index].vx * dtTime;
                const y = balls[index].y + balls[index].vy * dtTime;

                if (Math.abs(x - R) < 10 && Math.abs(y - H - R) < 10) {
                    ball.potted = true;

                    // Reset if potted
                    if (!ball.cue || ball.x > W - R || ball.y > H - R) {
                        balls[index] = {x: 100, y: 50, vx: 0, vy: 0, cue: false};
                    }
                }
            });

            // Draw all balls
            drawBalls();
        };

        // Function to pause/resume physics loop
        window.sim.pause() => {
            window.sim.resume();
        };

        // Function to shoot cue ball (via mouse control)
        function shoot(vx, vy) {
            const cueBall = {x: balls[0].x + balls[0].vx * dtTime, y: balls[0].y + balls[0].vy * dtTime, vx: vx, vy: vy, cue: true};

            // Update cue ball's position and velocity
            cueBall.x += vx * dtTime;
            cueBall.y += vy * dtTime;

            // Step physics for cue ball (same effect as mouse control)
            window.sim.step(dt);
        };

        // Function to draw balls on canvas
        function drawBalls() {
            const canvas = document.getElementById('canvas');
            const ctx = canvas.getContext('2d');

            // Clear canvas
            ctx.clearRect(0, 0, W, H);

            // Draw table boundaries (optional)
            ctx.fillStyle = '#ccc';
            ctx.fillRect(W - R, R, R, R); // bottom rail
            ctx.fillRect(W - R, H - R, R, R); // top rail

            // Draw balls
            balls.forEach(function(ball) {
                const ballX = ball.x + ball.vx * dtTime;
                const ballY = ball.y + ball.vy * dtTime;

                ctx.beginPath();
                ctx.arc(ballX, ballY, R, 0, Math.PI * 2);
                ctx.fillStyle = '#ff0000';
                ctx.fill();

                // Draw cue ball
                if (ball.cue) {
                    ctx.beginPath();
                    ctx.arc(ballX, ballY, R, 0, Math.PI * 2);
                    ctx.fillStyle = '#00ff00';
                    ctx.fill();
                }
            });

            // Draw instructions and reset button
            ctx.font = '12px Arial';
            ctx.fillStyle = '#333';
            ctx.textAlign = 'center';
            ctx.fillText('Playable Billiards Game', W/2, H - 10);
            ctx.textBaseline = 'top';

            // Reset button
            const resetBtn = document.createElement('button');
            resetBtn.innerHTML = 'Reset';
            resetBtn.style.cssText = `
                position: fixed;
                top: 20px;
                right: 20px;
                padding: 10px 15px;
                font-size: 14px;
                background-color: #4CAF50;
                color: white;
                border: none;
                cursor: pointer;
            `;
            resetBtn.onclick = function() {
                window.sim.reset(balls);
                alert('Game reset!');
            };

            canvas.appendChild(resetBtn);
        }

        // Initialize game state
        window.sim.state() = [...balls];
    </script>
</body>
</html>
